-- 041_lifecycle_benchmark_v2.sql
-- Re-seed algo_lifecycle_benchmark with the conditioned v2 cohort.
--
-- The v1 seed (migration 035) pooled ALL songs, so >80% non-triggering zeros crushed the
-- median ratio toward 0 and total_stream_median was left NULL (no live reference). v2 is
-- generated by `machine_learning/export_lifecycle_benchmark.py --version v2` conditioned on
-- the TRIGGERING cohort (28d algo streams clear the elbow: DW>137 / RR>130 / Radio>639),
-- min 5 songs per age bin. Result: meaningful medians + a real total_stream_median so the
-- "Cycle de vie & Benchmark" standardization overlay finally has a reference. v1 rows are
-- kept (UNIQUE is per dataset_version); the loader prefers v2 and falls back to v1.
--
-- Semantic note: the curve now reads "among songs that DID trigger, how does the lifecycle
-- look?" — not "all songs". RR only spans the 0–10 week window (it fires near release, so
-- older bins have too few triggering songs and are intentionally absent).
-- Idempotent via ON CONFLICT. Apply with `make migrate`.

INSERT INTO algo_lifecycle_benchmark (algorithm, weight_category_type, age_week_bin, age_week_bin_order, ratio_min, ratio_q1, ratio_median, ratio_q3, ratio_max, total_stream_median, sample_count, dataset_version) VALUES
    ('DW', 'follower_decile', '0-5', 1, 0.0846, 0.1635, 0.2102, 0.445, 3.9251, 18229.5, 14, 'v2'),
    ('DW', 'follower_decile', '5-10', 2, 0.0689, 0.2446, 0.9233, 1.4062, 2.9664, 30322.0, 15, 'v2'),
    ('DW', 'follower_decile', '10-25', 3, 0.0818, 0.2929, 0.7608, 1.7881, 4.5845, 17841.0, 17, 'v2'),
    ('DW', 'follower_decile', '25-50', 4, 0.1521, 0.3223, 0.5476, 1.4365, 4.0865, 17311.0, 23, 'v2'),
    ('DW', 'follower_decile', '50-100', 5, 0.0718, 0.3124, 0.583, 1.4771, 2.536, 28439.0, 16, 'v2'),
    ('DW', 'follower_decile', '100+', 6, 0.0693, 0.3825, 0.5799, 1.4479, 4.8362, 11508.0, 19, 'v2'),
    ('RR', 'follower_decile', '0-5', 1, 0.1681, 0.3414, 0.5392, 1.0679, 4.5023, 4337.5, 78, 'v2'),
    ('RR', 'follower_decile', '5-10', 2, 0.1058, 0.2797, 0.7886, 1.7447, 3.965, 6339.5, 22, 'v2'),
    ('RADIO', 'popularity_bucket', '0-5', 1, 0.0805, 0.5072, 0.7996, 1.1065, 2.6768, 6493.0, 80, 'v2'),
    ('RADIO', 'popularity_bucket', '5-10', 2, 0.0498, 0.2979, 0.5364, 0.7639, 2.8178, 12323.0, 31, 'v2'),
    ('RADIO', 'popularity_bucket', '10-25', 3, 0.0512, 0.5833, 1.0586, 1.7142, 2.6875, 11985.0, 25, 'v2'),
    ('RADIO', 'popularity_bucket', '25-50', 4, 0.1455, 0.5155, 0.9129, 1.2913, 2.2467, 18356.0, 32, 'v2'),
    ('RADIO', 'popularity_bucket', '50-100', 5, 0.2963, 0.5802, 0.7447, 1.5359, 10.7056, 18534.0, 33, 'v2'),
    ('RADIO', 'popularity_bucket', '100+', 6, 0.0963, 0.4811, 1.0373, 1.3147, 2.9622, 8660.5, 38, 'v2')
ON CONFLICT (algorithm, age_week_bin, dataset_version) DO UPDATE SET
    weight_category_type = EXCLUDED.weight_category_type, age_week_bin_order = EXCLUDED.age_week_bin_order, ratio_min = EXCLUDED.ratio_min, ratio_q1 = EXCLUDED.ratio_q1, ratio_median = EXCLUDED.ratio_median, ratio_q3 = EXCLUDED.ratio_q3, ratio_max = EXCLUDED.ratio_max, total_stream_median = EXCLUDED.total_stream_median, sample_count = EXCLUDED.sample_count,
    exported_at = CURRENT_TIMESTAMP;
